// python solution
import sys

class Solution:
    def solve(self, n: int) -> int:
        res = 0
        while n != 0:
            res += n & 1
            n >>= 1
        n = ~n
        while n != 0:
            res -= n & 1
            n >>= 1
        return res

n = int(sys.stdin.readline())
print(Solution().solve(n))

