// cpp solution
#include <iostream>

class Solution {
public:
    int solve(int n) {
        int res = 0;
        while (n != 0) {
            res += n & 1;
            n >>= 1;
        }
        n = ~n;
        while (n != 0) {
            res -= n & 1;
            n >>= 1;
        }
        return res;
    }
};

int main() {
    int n;
    std::cin >> n;
    Solution sol;
    std::cout << sol.solve(n) << std::endl;
    return 0;
}
